17	const quotePremium = (items: Item[]): number => {
18	  const policyBase = items.reduce((sum, item) => sum + basePremiumOf(item), 0);
19	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
20	  return policyBase + firstInsuranceSurcharge + PROCESSING_FEE;
